class Solution {
public:
bool solve(vector<int>& n, int w) {
	int N = n.size();
	if (w <= 0) return false;
	int** dp = new int*[N];
	for (int i = 0; i < N; i++) {
		if (i == 0) dp[i] = new int[w + 1];
		else dp[i] = dp[i - 1];
	}
	for (int i = 1; i < N; i++)
		for (int j = 1; j <= w; j++)
			if (j >= n[i]) dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - n[i]] + n[i]);
		else dp[i][j] = dp[i - 1][j];
	return dp[N - 1][w];
}
};

