#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
	int solve(vector<int>& n, int w) {
		int N = n.size();
		vector<vector<int>> dp(N + 1, vector<int>(w + 1));
		for (int i = 1; i <= N; i++)
			for (int j = 1; j <= w; j++)
				if (j >= n[i - 1]) dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - n[i - 1]] + n[i - 1]);
			else dp[i][j] = dp[i - 1][j];
		return dp[N][w];
	}
};

int main() {
	ios_base::sync_with_stdio(false); cin.tie(0);
	int N, W;
	cin >> N >> W;
